import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from "react-redux";
import { Typography } from '@material-ui/core';
import { inovateOSUtilStrings, inovateOSUtil } from '../../utils';
import { Subheader } from '../../../../includes';
import { inovateOSPageStrings } from '../config';
import { inovateOSPageActions } from '../actions';
import { ServiceItemBox } from '../InovateOSServices/ServicePage/ServiceItemBox';
const style = theme => ({
    root: {
    },
    subheader : {},
    subContainer : {},
    aboutus : {
        minHeight : "15cmå",
        margin : "100px 20px",
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
        [theme.breakpoints.up("md")] : {
            paddingRight : "25%",
            paddingLeft : "25%",
            textAlign : "center"
        }
    },
    title : {
        fontWeight : "bold",
        marginBottom : 50,
        borderBottom : "solid 5px " + inovateOSUtil.getTheme().appRed,
        color : inovateOSUtil.getTheme().primary,
    }
})
class _InovateOSAboutUs extends Component {
    componentDidMount() {
        const {
            dispatch,
            [inovateOSPageStrings.aboutUs] : aboutUs,
            [inovateOSPageStrings.attributes] : attributes,
        } = this.props;
        if(!aboutUs)
            inovateOSPageActions.getAboutUs()(dispatch);
        if(!attributes) inovateOSPageActions.getAttributs()(dispatch);
    }
    
    render() {
        const {
            classes,
            [inovateOSUtilStrings.subheadImage] : subheadImage,
            [inovateOSUtilStrings.backendBaseUrl] : baseUrl,
            [inovateOSPageStrings.aboutUs] : aboutUs,
            [inovateOSPageStrings.attributes] : attributes,
            userAlt,
        } = this.props;
        return (
            <div className={classes.root}>
                <Subheader
                    classes={{
                        root : classes.subheader,
                        overlay : classes.subContainer,
                    }}
                    image_url={subheadImage}
                    title="About Us"/>
                <div className={classes.subContainer}>
                    <div className={classes.aboutus}>
                        <Typography variant="h5"
                            className={classes.title}
                            paragraph>
                                ABOUT US
                            </Typography>
                        {aboutUs && aboutUs.value && aboutUs.value.map((item, index)=>{
                            return <Typography paragraph key={index}>{item}</Typography>
                        })}
                    </div>
                    <div style={{marginTop : 50}}>
                        <Typography variant="h5"
                            className={classes.title}
                            paragraph>
                                WHY CHOOSE US?
                            </Typography>
                        {attributes && attributes.map((item, index)=>{
                            item.paperProps = {style: {background : "transparent"}};
                            item.baseUrl=baseUrl;
                            item.headerLink = "";
                            return userAlt ? <ServiceItemBox 
                                classes={{root : classes.itemBox}}  
                                alt={index % 2 === 0} 
                                {...item} 
                                key={index}/>: 
                            <ServiceItemBox 
                                classes={{root : classes.itemBox}} 
                                {...item} 
                                key={index}/>
                        })}
                    </div>
                </div>
            </div>
        );
    }
}
_InovateOSAboutUs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({inovateOSUtilReducer, inovateOSPageReducer}) => ({
    [inovateOSUtilStrings.subheadImage] : inovateOSUtilReducer[inovateOSUtilStrings.subheadImage],
    [inovateOSUtilStrings.backendBaseUrl] : inovateOSUtilReducer[inovateOSUtilStrings.backendBaseUrl],
    [inovateOSPageStrings.aboutUs] : inovateOSPageReducer[inovateOSPageStrings.aboutUs],
    [inovateOSPageStrings.attributes] : inovateOSPageReducer[inovateOSPageStrings.attributes],
})
export const InovateOSAboutUs = connect(mapStateToProps)(withStyles(style)(_InovateOSAboutUs));
export {InovateOSAboutUs as default};